import{c as a,Q as t,j as i,m as o}from"./chunks/framework.CdiUUa3G.js";const g=JSON.parse('{"title":"ADR-033 — Translation workflow: LLM-only first-pass","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-033.md","filePath":"adr/ADR-033.md"}'),r={name:"adr/ADR-033.md"};function n(s,e,l,d,c,u){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-033-—-translation-workflow-llm-only-first-pass" tabindex="-1">ADR-033 — Translation workflow: LLM-only first-pass <a class="header-anchor" href="#adr-033-—-translation-workflow-llm-only-first-pass" aria-label="Permalink to &quot;ADR-033 — Translation workflow: LLM-only first-pass&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-04 RFC anchor · <code>docs/rfc/RFC-010.md</code> (closed by ADR-031 + ADR-032 + this ADR) Re-evaluation triggers · documented below</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>RFC-010 OQ-3 explored four candidate translation workflows: professional agency ($200–400 / language), community PR model, AI-assisted with native-speaker review, and a hybrid by language tier. The decision was deferred to maintainer judgement. This ADR closes that question for v0.3.x and the immediate roadmap.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>LLM-only first-pass translation. No native-speaker review pass for v0.3.x.</strong></p><p>Concretely:</p><ul><li>An LLM (the same Claude that maintains this codebase) produces the first pass for every locale-overlay file (<code>static/data/i18n/&lt;code&gt;/...</code>) and the Paraglide message bundle (<code>messages/&lt;code&gt;.json</code>).</li><li>The physics-terminology glossary at <code>docs/guides/i18n-style-guide.md</code> (per ADR-017&#39;s content rules; authored under #34) is the LLM&#39;s binding brief — terms in that glossary are non-negotiable.</li><li>Mission and agency proper nouns (Curiosity, Perseverance, JAXA, ROSCOSMOS, etc.) stay in original language per PRD-007 §translation-guidance.</li><li>No human native-speaker review gate before merge. Quality risk is accepted.</li></ul><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The maintainer is a single individual operating a side-project; there is no translation budget, no translator network, and no ongoing review capacity. The realistic choice is between &quot;LLM-only and shipped&quot; vs &quot;human-reviewed and never shipped&quot;. The PRD&#39;s reach goal (1.5B+ speakers excluded by English-only state) outweighs the quality risk of imperfect translations, <em>provided</em> graceful degradation exists.</p><p>Graceful degradation is already in place via ADR-017&#39;s en-US fallback chain: any missing or broken <code>&lt;code&gt;</code> overlay falls back to en-US per-key, so a bad translation never breaks the user&#39;s session — at worst it shows English fallback. This means the cost of a translation error is bounded (English fallback) rather than user-blocking (broken UI).</p><p>The glossary (#34) is the load-bearing quality control: it constrains the high-stakes physics terminology (<code>Δv</code>, Hohmann transfer, sphere of influence, etc.) where literal translation would be actively wrong. Outside the glossary, descriptive prose tolerates more variation.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Professional agency for tier-1 languages, LLM for the rest</strong> — proper hybrid; rejected on budget grounds (no budget). Re-evaluation trigger if budget materialises.</li><li><strong>Community PR model</strong> — open <code>translations/</code> and let contributors submit per-language PRs; rejected because cold-start needs a populated first language and a glossary, and quality review still falls on the maintainer. Re-evaluation trigger if a community contributor offers ongoing native-speaker review.</li><li><strong>AI-assisted with mandatory native review</strong> — gold standard; rejected because there is no review capacity and &quot;mandatory review&quot; would mean &quot;never shipped&quot;.</li><li><strong>No translations</strong> — keeps quality at &quot;perfect English&quot; but excludes ~3B speakers; rejected on PRD grounds.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong></p><ul><li>Spanish (and future locales) ship at maintainer pace, not blocked on external review capacity.</li><li>Cost = $0 per language; scales to all eleven without budget approval.</li><li>Fallback chain bounds the user-visible cost of any translation error.</li></ul><p><strong>Negative:</strong></p><ul><li>Physics terminology can drift if the glossary is incomplete or the LLM ignores it. Mitigation: spot-check 5 random missions per locale before commit; treat glossary maintenance as load-bearing.</li><li>Idiomatic naturalness will be uneven. Spanish from a tuned LLM is probably good; Hindi or Arabic from the same LLM is less verifiable without a native speaker.</li><li>Cultural adaptation (regional idioms, formal-vs-informal register choice) happens by LLM judgement rather than informed editorial choice.</li><li>This ADR is explicitly opinionated about quality vs reach; future maintainers may disagree and trigger re-evaluation.</li></ul><h2 id="re-evaluation-triggers" tabindex="-1">Re-evaluation triggers <a class="header-anchor" href="#re-evaluation-triggers" aria-label="Permalink to &quot;Re-evaluation triggers&quot;">​</a></h2><p>Supersede or extend this ADR when any of the following happens:</p><ol><li><strong>First user-reported translation issue</strong> — particularly a physics-terminology error or a culturally inappropriate phrasing. Don&#39;t wait for accumulation; one credible report should trigger glossary update + LLM re-translation of affected files.</li><li><strong>A native-speaker reviewer becomes available</strong> for any specific language (paid or volunteer). At that point, that language moves to &quot;AI-assisted + native review&quot; and this ADR is superseded for that locale only.</li><li><strong>Budget materialises</strong> for professional translation of a tier-1 language. At that point, hybrid-by-tier becomes feasible and this ADR is superseded.</li><li><strong>An LLM regression</strong> in translation quality is observed across multiple locales. At that point, the LLM-only pillar weakens and the workflow is re-opened.</li></ol><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>The glossary at <code>docs/guides/i18n-style-guide.md</code> is part of the translator brief (whether LLM or human); changes to the glossary should ideally trigger re-translation of affected files.</li><li>Per-language tickets (e.g. #17 for Spanish) reference this ADR in their workflow section and link the glossary as a binding input.</li><li>This ADR does not prevent a per-language ticket from layering review on top of the LLM pass — it documents the <em>baseline</em>, not the <em>ceiling</em>.</li></ul>',24)])])}const p=a(r,[["render",n]]);export{g as __pageData,p as default};
